import React, { useState, useEffect } from 'react';
import { BrowserRouter, Routes, Route } from 'react-router-dom';
import './App.css';
import Login from './components/login';
import Signup from './components/signup';
import Landing from './components/Landing';
import AdminDashboard from './components/AdminDashboard'; 

function AuthPage() {
  const [isSignup, setIsSignup] = useState(false);
  const [loginBanner, setLoginBanner] = useState('');
  const [isLoading, setIsLoading] = useState(true); // NEW: Loading state

  useEffect(() => {
    // NEW: 'no-store' forces the browser to get fresh data every single time
    fetch('http://localhost:8000/api/assets', { cache: 'no-store' })
      .then(res => res.json())
      .then(data => {
        if (data.status === 'success' && data.assets.login_banner) {
          setLoginBanner(data.assets.login_banner);
        }
        setIsLoading(false);
      })
      .catch(err => {
        console.error("Banner fetch failed", err);
        setIsLoading(false);
      });
  }, []);

  // Show a smooth dark background while loading to prevent old image flashes
  const dynamicBackground = {
    backgroundImage: isLoading ? 'none' : (loginBanner ? `url(${loginBanner})` : 'linear-gradient(45deg, #050505, #1a1a1a)'),
    backgroundColor: '#0a0a0a',
    backgroundSize: 'cover',
    backgroundPosition: 'center',
    transition: 'background-image 0.5s ease-in-out'
  };

  return (
    <div className="auth-wrapper">
      <div 
        className={`sliding-image ${isSignup ? 'move-right' : ''}`}
        style={dynamicBackground}
      ></div>
      <div className={`sliding-form ${isSignup ? 'move-left' : ''}`}>
        {isSignup ? (
          <Signup toggleSlide={() => setIsSignup(false)} />
        ) : (
          <Login toggleSlide={() => setIsSignup(true)} />
        )}
      </div>
    </div>
  );
}

function App() {
  return (
    <BrowserRouter>
      <Routes>
        <Route path="/" element={<AuthPage />} />
        <Route path="/landing" element={<Landing />} />
        <Route path="/admin" element={<AdminDashboard />} />
      </Routes>
    </BrowserRouter>
  );
}

export default App;
